    ADDR_CTRL_MEM_DATA_17  = 8'h54,
    ADDR_CTRL_MEM_DATA_18  = 8'h58,
    ADDR_CTRL_MEM_DATA_19  = 8'h5c,
    ADDR_CTRL_MEM_DATA_20  = 8'h60,
